{
  "terms": [
    {
      "term": "TT System",
      "simpleDefinition": "An earthing arrangement where the consumer provides their own connection to Earth, usually via a rod in the ground.",
      "anchor": "The consumer's own rod in the soil.",
      "misconception": "Thinking the supplier provides the earth connection in this system."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth conductors are separate throughout the entire supply network.",
      "anchor": "Separate neutral and earth all the way from the transformer.",
      "misconception": "Confusing it with TN-C-S because both use the supplier's earth cable."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An earthing arrangement where neutral and earth are combined in the supply cable but separated at the consumer's intake.",
      "anchor": "Combined in the street, separated at the house.",
      "misconception": "Believing the earth and neutral stay combined inside the building's final circuits."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety method that automatically cuts off power during a fault to prevent electric shock.",
      "anchor": "The system's 'kill switch' for electrical faults.",
      "misconception": "Thinking ADS is a single component rather than a combination of parts working together."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific wire in a circuit that connects metal equipment parts to the main earthing terminal.",
      "anchor": "The green and yellow wire inside a circuit cable.",
      "misconception": "Using the term 'earthing conductor' when referring to a circuit's CPC."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's earthing terminal to the means of earthing (like a rod or supplier terminal).",
      "anchor": "The single main link between the house and the Earth itself.",
      "misconception": "Thinking this is the same as the CPCs found in individual circuits."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal services like gas and water pipes to the main earthing terminal.",
      "anchor": "Connecting the main pipes to the earth terminal.",
      "misconception": "Thinking bonding is designed to carry circuit current under normal conditions."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod or plate buried in the ground to provide a physical connection to the Earth.",
      "anchor": "The physical metal rod driven into the ground.",
      "misconception": "Believing every earthing system requires a rod in the garden."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component like a fuse or circuit breaker that automatically breaks the circuit during a fault.",
      "anchor": "The fuse or MCB that trips to stop the power.",
      "misconception": "Thinking these only protect against 'too many appliances' rather than dangerous faults."
    }
  ],
  "anchorPhrases": [
    "Combined in the street, separated at the house",
    "The consumer's own rod in the soil",
    "Separate neutral and earth all the way",
    "The system's 'kill switch' for faults",
    "The single main link to the Earth"
  ],
  "misconceptionTargets": [
    "Terms in this lesson are distinct and must be used precisely.",
    "The earthing conductor and the CPC are not the same thing.",
    "TN-S and TN-C-S are different because of how the neutral and earth are handled in the supply.",
    "ADS is a system of parts, not just one device."
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "Earthing systems describe how an electrical installation connects to the general mass of Earth to ensure safety. There are three primary types you must identify. In a TT system, the supplier does not provide an earth connection. Instead, the consumer provides their own connection to the ground, usually by driving a metal earth electrode, such as a rod, into the soil.",
        "In a TN-S system, the 'S' stands for 'Separate'. This means the neutral and earth conductors are separate cables throughout the entire network, from the transformer all the way to the consumer's intake. In a TN-C-S system, the 'C' stands for 'Combined'. Here, the neutral and earth are combined into a single conductor in the street supply but are separated into two distinct terminals once they reach the consumer's property. This combined arrangement is common in modern UK housing and is often called PME (Protective Multiple Earthing)."
      ],
      "hint": "Focus on whether the earth and neutral are separate (S) or combined (C) in the supply cable, and remember that TT requires the consumer's own rod."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that facilitate Automatic Disconnection of Supply.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is not a single component; it is a safety method that uses several parts to 'kill' the power during a fault. The earthing conductor is the main link that connects the installation's earthing terminal to the earth source (like a rod or the supplier's cable). Do not confuse this with the Circuit Protective Conductor (CPC), which is the green and yellow wire found inside individual circuit cables that connects metal equipment to the main terminal.",
        "To ensure safety across the whole building, main protective bonding conductors connect metal services like gas and water pipes to the main earthing terminal. In high-risk areas, supplementary bonding may also be used to link metal parts together. The final part of the ADS system is the protective device, such as a circuit breaker (MCB) or RCD. This is the component that physically trips to stop the flow of electricity when a fault occurs."
      ],
      "hint": "Think of the earthing conductor as the main link to the ground, while the CPC is the wire inside your circuit cables."
    }
  ]
}

